package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";

    // Use the class directly instead of Class.forName to avoid ClassNotFoundException
    Class<LineItem> lineItemClass = LineItem.class;
    Constructor<LineItem> constructor = lineItemClass.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance("itemName", 2, 1000L, expectedCurrencyCode);

    // Invoke getCurrencyCode method via reflection
    String actualCurrencyCode = (String) lineItemClass.getMethod("getCurrencyCode").invoke(lineItem);

    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
